def _run(cmd: list[str]) -> tuple[int, str]:
    result = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True)
    return result.returncode, result.stdout


def _run_timed(cmd: list[str]) -> tuple[int, str, int]:
    started = time.perf_counter()
    returncode, stdout = _run(cmd)
    duration_ms = int(round((time.perf_counter() - started) * 1000))
    return returncode, stdout, duration_ms


def _load_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    return json.loads(path.read_text(encoding="utf-8"))


def _whitespace_metadata_failure(
    payload: Any,
    *,
    label: str,
    max_exterior_fraction: float,
) -> dict[str, Any] | None:
    if not isinstance(payload, dict):
        return {"label": label, "reason": "missing_metadata"}
    if payload.get("checked") is not True:
        return {
            "label": label,
            "reason": "not_checked",
            "metadata_reason": payload.get("reason", ""),
        }
    fraction = payload.get("exterior_fraction")
    if not isinstance(fraction, (int, float)) or isinstance(fraction, bool):
        return {"label": label, "reason": "missing_exterior_fraction"}
    if fraction > max_exterior_fraction:
        return {
            "label": label,
            "reason": "exterior_fraction_high",
            "max_exterior_fraction": max_exterior_fraction,
            "actual_exterior_fraction": fraction,
        }
    return None


def _inject_planning_contract_warnings(workspace: Path) -> str:
    try:
        design_path = workspace / "design_brief.json"
        design_brief = _load_json(design_path)
        readability_contract = design_brief.get("readability_contract")
        if not isinstance(readability_contract, dict):
            readability_contract = {}
        readability_contract["min_body_pt"] = 8
        readability_contract["whitespace_rule"] = ""
        design_brief["readability_contract"] = readability_contract
        speed_contract = design_brief.get("speed_contract")
        if not isinstance(speed_contract, dict):
            speed_contract = {}
        speed_contract["conversion_hint"] = ""
        design_brief["speed_contract"] = speed_contract
        design_path.write_text(json.dumps(design_brief, indent=2) + "\n", encoding="utf-8")
    except (OSError, json.JSONDecodeError) as exc:
        return str(exc)
    return ""


def _inject_planning_data_source_fingerprint_warning(workspace: Path) -> tuple[str, str]:
    data_text = "Sample,Signal\nA01,42.1\nA02,39.4\n"
    try:
        data_dir = workspace / "data"
        data_dir.mkdir(parents=True, exist_ok=True)
        (data_dir / "run_a.csv").write_text(data_text, encoding="utf-8")
        design_path = workspace / "design_brief.json"
        design_brief = _load_json(design_path)
        plan = design_brief.get("analysis_artifact_plan")
        if not isinstance(plan, dict):
            plan = {}
        plan.update(
            {
                "candidate_data_files": ["data/run_a.csv"],
                "data_source_fingerprints": [
                    {
                        "path": "data/run_a.csv",
                        "source_sha256": "stale-delivery-data-source-sha",
                        "source_size_bytes": 1,
                    }
                ],
                "spreadsheet_inputs": [],
                "required_scripts": [],
                "figure_scripts": [],
                "chart_json_outputs": [],
                "table_outputs": [],
                "rebuild_commands": [],
            }
        )
        design_brief["analysis_artifact_plan"] = plan
        design_path.write_text(json.dumps(design_brief, indent=2) + "\n", encoding="utf-8")
    except (OSError, json.JSONDecodeError) as exc:
        return str(exc), data_text
    return "", data_text


def _inject_delivery_qa_whitespace_warning(workspace: Path) -> str:
    try:
        qa_report_path = workspace / "build" / "qa" / "report.json"
        build_report_path = workspace / "build" / "build_workspace_report.json"
        qa_payload = _load_json(qa_report_path)
        if not isinstance(qa_payload, dict):
            qa_payload = {}
        whitespace_warnings = (
            qa_payload.get("whitespace_warnings")
            if isinstance(qa_payload.get("whitespace_warnings"), list)
            else []
        )
        whitespace_warnings.append(
            {
                "type": "content_span_too_short",
                "severity": "warning",
                "slide_index": 1,
                "slide_id": "s2",
                "slide_type": "content",
                "variant": "standard",
                "shape_id": "content-block",
                "content_span_height_ratio": 0.22,
                "max_vertical_dead_ratio": 0.58,
                "suggested_fix": (
                    "Enlarge the evidence block, add a visual/table/sidebar, "
                    "or choose an intentional sparse variant."
                ),
            }
        )
        qa_payload["whitespace_warnings"] = whitespace_warnings
        qa_payload["whitespace_warning_count"] = len(whitespace_warnings)
        qa_payload["geometry_warning_count"] = max(
            int(qa_payload.get("geometry_warning_count") or 0),
            len(whitespace_warnings),
        )
        qa_report_path.write_text(json.dumps(qa_payload, indent=2) + "\n", encoding="utf-8")

        build_payload = _load_json(build_report_path)
        if not isinstance(build_payload, dict):
            build_payload = {}
        reports = build_payload.setdefault("reports", {})
        if not isinstance(reports, dict):
            reports = {}
            build_payload["reports"] = reports
        qa_report = reports.setdefault("qa", {})
        if not isinstance(qa_report, dict):
            qa_report = {}
            reports["qa"] = qa_report
        qa_report["path"] = "build/qa/report.json"
        qa_report["exists"] = True
        counts = qa_report.setdefault("counts", {})
        if not isinstance(counts, dict):
            counts = {}
            qa_report["counts"] = counts
        counts["whitespace_warning_count"] = len(whitespace_warnings)
        counts["geometry_warning_count"] = max(
            int(counts.get("geometry_warning_count") or 0),
            len(whitespace_warnings),
        )
        build_report_path.write_text(
            json.dumps(build_payload, indent=2) + "\n",
            encoding="utf-8",
        )
    except (OSError, json.JSONDecodeError, TypeError, ValueError) as exc:
        return str(exc)
    return ""


def _sha256_text(text: str) -> str:
    return hashlib.sha256(text.encode("utf-8")).hexdigest()


def _deck_text(path: Path) -> str:
    if not path.exists():
        return ""
    prs = Presentation(str(path))
    chunks: list[str] = []
    for slide in prs.slides:
        for shape in slide.shapes:
            if getattr(shape, "has_table", False):
                for row in shape.table.rows:
                    for cell in row.cells:
                        chunks.append(cell.text)
            text = getattr(shape, "text", "")
            if text:
                chunks.append(text)
    return "\n".join(chunks)


def _regression_file_snapshot(workspace: Path, path: Path) -> dict[str, Any]:
    try:
        display_path = str(path.resolve().relative_to(workspace.resolve()))
    except ValueError:
        display_path = str(path.resolve())
    snapshot: dict[str, Any] = {
        "path": display_path,
        "exists": path.exists(),
    }
    if path.exists() and path.is_file():
        payload = path.read_bytes()
        snapshot["size_bytes"] = len(payload)
        snapshot["sha256"] = hashlib.sha256(payload).hexdigest()
        if is_office_package_path(path):
            try:
                snapshot["normalized_sha256"] = office_package_normalized_sha256(path)
                snapshot["normalized_sha256_algorithm"] = OFFICE_PACKAGE_HASH_ALGORITHM
            except Exception as exc:
                snapshot["normalized_hash_error"] = str(exc)
    return snapshot


def _write_synthetic_current_qa_whitespace_build_report(
    workspace: Path,
    *,
    slide_index: int,
    warning_type: str = "content_span_too_short",
    design_warning_type: str = "",
    visual_warning_count: int = 0,
    visual_warning_type: str = "underfilled_textbox",
    run_status: str = "succeeded",
    returncode: int = 0,
    failed_step: str = "",
) -> None:
    qa_report = workspace / "build" / "qa" / "report.json"
    qa_report.parent.mkdir(parents=True, exist_ok=True)
    whitespace_warnings = []
    if warning_type:
        whitespace_warnings.append(
            {
                "type": warning_type,
                "severity": "warning",
                "slide_index": slide_index,
                "slide_type": "content",
                "variant": "standard",
                "content_span_height_ratio": 0.22,
                "max_vertical_dead_ratio": 0.58,
                "suggested_fix": "Enlarge the evidence block, add a visual/table/sidebar, or choose an intentional sparse variant.",
            }
        )
    design_report = qa_report.parent / "design_rules.json"
    design_warnings = []
    if design_warning_type:
        design_warnings.append(
            {
                "slide_index": slide_index,
                "shape_id": "shape-2",
                "type": design_warning_type,
                "severity": "warning",
                "role": "body",
                "font_pt": 8.0,
                "min_allowed_pt": 12.0,
                "text": "Synthetic text is below the readable body threshold.",
            }
        )
    design_report.write_text(
        json.dumps(
            {
                "issue_count": len(design_warnings),
                "error_count": 0,
                "warning_count": len(design_warnings),
                "issues": design_warnings,
                "passed": not design_warnings,
            },
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )
    visual_report = qa_report.parent / "visual_qa.json"
    visual_warnings = []
    for _idx in range(max(0, int(visual_warning_count or 0))):
        visual_warnings.append(
            {
                "slide": slide_index + 1,
                "severity": "warning",
                "type": visual_warning_type,
                "shape": "Synthetic TextBox",
                "position": "(1.2, 2.1)",
                "fill_pct": 18,
                "suggestion": "Densify content, reduce container height, or add a visual anchor.",
            }
        )
    visual_report.write_text(
        json.dumps(visual_warnings, indent=2) + "\n",
        encoding="utf-8",
    )
    qa_report.write_text(
        json.dumps(
            {
                "whitespace_warning_count": len(whitespace_warnings),
                "geometry_warning_count": len(whitespace_warnings),
                "geometry_error_count": 0,
                "overflow_count": 0,
                "overlap_count": 0,
                "design_error_count": 0,
                "design_warning_count": len(design_warnings),
                "design_report": str(design_report),
                "visual_warning_count": len(visual_warnings),
                "visual_report": str(visual_report),
                "visual_review_warning_count": 0,
                "whitespace_warnings": whitespace_warnings,
            },
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )
    source_paths = {
        "workspace_manifest": workspace / "workspace.json",
        "style_contract": workspace / "style_contract.json",
        "design_brief": workspace / "design_brief.json",
        "content_plan": workspace / "content_plan.json",
        "evidence_plan": workspace / "evidence_plan.json",
        "asset_plan": workspace / "asset_plan.json",
        "outline_source": workspace / "outline.json",
        "outline_used": workspace / "outline.json",
        "artifact_manifest": workspace / "assets" / "artifacts_manifest.json",
    }
    build_report = {
        "schema_version": 1,
        "workspace": str(workspace),
        "run": {
            "status": run_status,
            "returncode": returncode,
            "failed_step": failed_step,
            "step_returncodes": {failed_step: returncode} if failed_step else {},
        },
        "style_preset": "lab-report",
        "renderer": {"requested": "auto", "used": "pptxgenjs"},
        "source_files": {
            name: _regression_file_snapshot(workspace, path)
            for name, path in source_paths.items()
        },
        "outputs": {
            "pptx": {"path": "build/deck.pptx", "exists": False},
            "build_dir": "build",
        },
        "reports": {
            "qa": {
                "path": "build/qa/report.json",
                "exists": True,
                "counts": {
                    "whitespace_warning_count": len(whitespace_warnings),
                    "geometry_warning_count": len(whitespace_warnings),
                    "geometry_error_count": 0,
                    "overflow_count": 0,
                    "overlap_count": 0,
                    "design_error_count": 0,
                    "design_warning_count": len(design_warnings),
                    "visual_warning_count": len(visual_warnings),
                    "visual_review_warning_count": 0,
                },
            }
        },
    }
    (workspace / "build" / "build_workspace_report.json").write_text(
        json.dumps(build_report, indent=2) + "\n",
        encoding="utf-8",
    )


