def _run_strict_qa_failure_build_report_regression(
    repo: Path,
    outdir: Path,
    py: str,
) -> dict[str, Any]:
    case_dir = outdir / "strict-qa-failure-build-report-gate"
    if case_dir.exists():
        shutil.rmtree(case_dir)
    workspace = case_dir / "workspace"

    init_rc, init_out = _run(
        [
            py,
            str(repo / "scripts" / "init_deck_workspace.py"),
            "--workspace",
            str(workspace),
            "--title",
            "Strict QA Failure Report Regression",
            "--style-preset",
            "lab-report",
        ]
    )
    mutation_error = ""
    if init_rc == 0:
        try:
            design_path = workspace / "design_brief.json"
            design_brief = _load_json(design_path)
            contract = design_brief.setdefault("readability_contract", {})
            contract["min_title_pt"] = 42
            contract["min_body_pt"] = 36
            contract["min_caption_pt"] = 22
            contract["chart_label_min_pt"] = 16
            design_path.write_text(json.dumps(design_brief, indent=2) + "\n", encoding="utf-8")
        except (OSError, json.JSONDecodeError) as exc:
            mutation_error = str(exc)

    build_rc = 99
    build_out = ""
    if init_rc == 0 and not mutation_error:
        build_rc, build_out = _run(
            [
                py,
                str(repo / "scripts" / "build_workspace.py"),
                "--workspace",
                str(workspace),
                "--qa",
                "--skip-render",
                "--overwrite",
            ]
        )

    build_report_path = workspace / "build" / "build_workspace_report.json"
    qa_report_path = workspace / "build" / "qa" / "report.json"
    build_report = _load_json(build_report_path)
    qa_report = _load_json(qa_report_path)
    run = build_report.get("run", {}) if isinstance(build_report, dict) else {}
    step_returncodes = run.get("step_returncodes", {}) if isinstance(run, dict) else {}
    reports = build_report.get("reports", {}) if isinstance(build_report, dict) else {}
    report_qa = reports.get("qa", {}) if isinstance(reports, dict) else {}
    report_qa_counts = report_qa.get("counts", {}) if isinstance(report_qa, dict) else {}
    outputs = build_report.get("outputs", {}) if isinstance(build_report, dict) else {}
    pptx_output = outputs.get("pptx", {}) if isinstance(outputs, dict) else {}

    readiness_rc = 99
    readiness_out = ""
    if build_report_path.exists():
        readiness_rc, readiness_out = _run(
            [
                py,
                str(repo / "scripts" / "report_workspace_readiness.py"),
                "--workspace",
                str(workspace),
            ]
        )
    readiness_report_path = workspace / "build" / "workspace_readiness.json"
    readiness_markdown_path = workspace / "build" / "workspace_readiness.md"
    readiness_report = _load_json(readiness_report_path)
    readiness_markdown = (
        readiness_markdown_path.read_text(encoding="utf-8")
        if readiness_markdown_path.exists()
        else ""
    )
    recommendations = (
        readiness_report.get("recommendations", [])
        if isinstance(readiness_report, dict)
        else []
    )
    rec_kinds = {
        str(item.get("kind") or "")
        for item in recommendations
        if isinstance(item, dict)
    }
    readiness_next = (
        readiness_report.get("next_action", {}) if isinstance(readiness_report, dict) else {}
    )
    last_build = readiness_report.get("last_build", {}) if isinstance(readiness_report, dict) else {}

    delivery_rc = 99
    delivery_out = ""
    if build_report_path.exists():
        delivery_rc, delivery_out = _run(
            [
                py,
                str(repo / "scripts" / "report_delivery_readiness.py"),
                "--workspace",
                str(workspace),
                "--allow-skip-render",
            ]
        )
    delivery_report_path = workspace / "build" / "delivery_readiness.json"
    delivery_markdown_path = workspace / "build" / "delivery_readiness.md"
    delivery_report = _load_json(delivery_report_path)
    delivery_markdown = (
        delivery_markdown_path.read_text(encoding="utf-8")
        if delivery_markdown_path.exists()
        else ""
    )
    delivery_blocking = (
        set(delivery_report.get("blocking_reasons", []))
        if isinstance(delivery_report, dict)
        else set()
    )
    delivery_gates = delivery_report.get("gates", {}) if isinstance(delivery_report, dict) else {}

    advance_rc = 99
    advance_out = ""
    if build_report_path.exists():
        advance_rc, advance_out = _run(
            [
                py,
                str(repo / "scripts" / "advance_delivery.py"),
                "--workspace",
                str(workspace),
                "--allow-skip-render",
            ]
        )
    advance_report_path = workspace / "build" / "delivery_advance_report.json"
    advance_prompt_path = workspace / "build" / "delivery_next_action.md"
    advance_report = _load_json(advance_report_path)
    advance_prompt = advance_prompt_path.read_text(encoding="utf-8") if advance_prompt_path.exists() else ""
    advance_edit_plan = (
        advance_report.get("source_edit_plan", [])
        if isinstance(advance_report.get("source_edit_plan"), list)
        else []
    )
    advance_first_measurement_edit = next(
        (
            item
            for item in advance_edit_plan
            if isinstance(item, dict)
            and item.get("font_pt") not in (None, "")
            and item.get("min_allowed_pt") not in (None, "")
        ),
        {},
    )

    passed = (
        init_rc == 0
        and not mutation_error
        and build_rc == 1
        and build_report_path.exists()
        and qa_report_path.exists()
        and run.get("status") == "failed"
        and run.get("returncode") == 1
        and run.get("failed_step") == "qa"
        and step_returncodes.get("qa") == 1
        and pptx_output.get("exists") is True
        and qa_report.get("design_warning_count", 0) > 0
        and report_qa_counts.get("design_warning_count", 0) > 0
        and readiness_rc == 1
        and readiness_report.get("status") == "needs_attention"
        and last_build.get("run_status") == "failed"
        and "polish_qa_design_warnings" in rec_kinds
        and "inspect_failed_build_report" in rec_kinds
        and readiness_next.get("kind") == "polish_qa_design_warnings"
        and "Build status: `failed`" in readiness_markdown
        and delivery_rc == 2
        and delivery_report.get("delivery_status") == "blocked"
        and "qa_step_failed" in delivery_blocking
        and delivery_gates.get("build_succeeded") is False
        and "Build status: `failed`" in delivery_markdown
        and advance_rc == 1
        and advance_report.get("decision") == "edit_sources_required"
        and advance_report.get("final_recommended_next_action", {}).get("kind") == "polish_qa_design_warnings"
        and advance_report.get("source_edit_plan_error", "") == ""
        and bool(advance_first_measurement_edit)
        and "font pt:" in advance_prompt
        and "min pt:" in advance_prompt
        and "readability contract" in advance_prompt
    )
    return {
        "case": "strict-qa-failure-build-report-gate",
        "passed": passed,
        "workspace": str(workspace),
        "init_rc": init_rc,
        "build_rc": build_rc,
        "run": run,
        "qa_design_warning_count": qa_report.get("design_warning_count"),
        "report_qa_counts": report_qa_counts,
        "readiness_rc": readiness_rc,
        "readiness_status": readiness_report.get("status"),
        "readiness_next_action": readiness_next.get("kind"),
        "readiness_rec_kinds": sorted(rec_kinds),
        "delivery_rc": delivery_rc,
        "delivery_status": delivery_report.get("delivery_status"),
        "delivery_blocking": sorted(delivery_blocking),
        "delivery_gates": delivery_gates,
        "advance_rc": advance_rc,
        "advance_decision": advance_report.get("decision"),
        "advance_next_action": advance_report.get("final_recommended_next_action", {}).get("kind"),
        "advance_source_edit_plan_count": len(advance_edit_plan),
        "advance_first_measurement_edit": advance_first_measurement_edit,
        "mutation_error": mutation_error,
        "init_stdout_tail": init_out[-1200:],
        "build_stdout_tail": build_out[-1600:],
        "readiness_stdout_tail": readiness_out[-1200:],
        "delivery_stdout_tail": delivery_out[-1200:],
        "advance_stdout_tail": advance_out[-1200:],
    }


def _run_workspace_readability_contract_scaffold_regression(
    repo: Path,
    outdir: Path,
    py: str,
) -> dict[str, Any]:
    case_dir = outdir / "workspace-readability-contract-scaffold-gate"
    if case_dir.exists():
        shutil.rmtree(case_dir)
    case_dir.mkdir(parents=True, exist_ok=True)

    init_rc, init_out = _run(
        [
            py,
            str(repo / "scripts" / "init_deck_workspace.py"),
            "--workspace",
            str(case_dir),
            "--title",
            "Workspace Readability Contract Scaffold Regression",
            "--style-preset",
            "lab-report",
        ]
    )

    design_brief = _load_json(case_dir / "design_brief.json")
    contract = design_brief.get("readability_contract") if isinstance(design_brief, dict) else {}
    required_keys = {
        "min_title_pt",
        "min_body_pt",
        "min_caption_pt",
        "max_title_lines",
        "max_slide_text_lines",
        "max_slide_words",
        "max_slide_chars",
        "footer_reserved_inches",
        "chart_label_min_pt",
        "table_density_rule",
        "whitespace_rule",
        "figure_crop_rule",
    }
    present_keys = set(contract) if isinstance(contract, dict) else set()
    missing_keys = sorted(required_keys - present_keys)

    report_path = case_dir / "planning_validation.json"
    validate_rc = 99
    validate_out = ""
    planning_payload: dict[str, Any] = {}
    if init_rc == 0:
        validate_rc, validate_out = _run(
            [
                py,
                str(repo / "scripts" / "validate_planning.py"),
                "--workspace",
                str(case_dir),
                "--report",
                str(report_path),
            ]
        )
        planning_payload = _load_json(report_path)
    readability_warnings = [
        item
        for item in planning_payload.get("issues", [])
        if isinstance(item, dict)
        and str(item.get("path") or "").startswith("design_brief.readability_contract")
    ]
    bad_report_path = case_dir / "planning_validation_bad_readability.json"
    bad_validate_rc = 99
    bad_validate_out = ""
    bad_planning_payload: dict[str, Any] = {}
    expected_bad_warning_paths = {
        "design_brief.readability_contract.min_title_pt",
        "design_brief.readability_contract.min_body_pt",
        "design_brief.readability_contract.min_caption_pt",
        "design_brief.readability_contract.chart_label_min_pt",
        "design_brief.readability_contract.footer_reserved_inches",
        "design_brief.readability_contract.max_title_lines",
        "design_brief.readability_contract.max_slide_text_lines",
        "design_brief.readability_contract.max_slide_words",
        "design_brief.readability_contract.max_slide_chars",
        "design_brief.readability_contract.table_density_rule",
        "design_brief.readability_contract.whitespace_rule",
        "design_brief.readability_contract.figure_crop_rule",
    }
    if init_rc == 0 and isinstance(design_brief, dict):
        bad_design_brief = dict(design_brief)
        bad_design_brief["readability_contract"] = {
            "min_title_pt": True,
            "min_body_pt": 11,
            "min_caption_pt": 7,
            "chart_label_min_pt": False,
            "footer_reserved_inches": 0.1,
            "max_title_lines": 0,
            "max_slide_text_lines": 0,
            "max_slide_words": -1,
            "max_slide_chars": False,
            "table_density_rule": "",
            "whitespace_rule": "",
            "figure_crop_rule": "",
        }
        (case_dir / "design_brief.json").write_text(
            json.dumps(bad_design_brief, indent=2) + "\n",
            encoding="utf-8",
        )
        bad_validate_rc, bad_validate_out = _run(
            [
                py,
                str(repo / "scripts" / "validate_planning.py"),
                "--workspace",
                str(case_dir),
                "--report",
                str(bad_report_path),
            ]
        )
        bad_planning_payload = _load_json(bad_report_path)
    bad_readability_warnings = [
        item
        for item in bad_planning_payload.get("issues", [])
        if isinstance(item, dict)
        and str(item.get("severity") or "") == "warning"
        and str(item.get("path") or "").startswith("design_brief.readability_contract")
    ]
    bad_warning_paths = {str(item.get("path") or "") for item in bad_readability_warnings}
    missing_bad_warning_paths = sorted(expected_bad_warning_paths - bad_warning_paths)

    passed = (
        init_rc == 0
        and isinstance(contract, dict)
        and not missing_keys
        and validate_rc in (0, 1)
        and not readability_warnings
        and bad_validate_rc == 1
        and bad_planning_payload.get("error_count") == 0
        and not missing_bad_warning_paths
    )
    return {
        "case": "workspace-readability-contract-scaffold-gate",
        "passed": passed,
        "workspace": str(case_dir),
        "init_rc": init_rc,
        "validate_rc": validate_rc,
        "missing_keys": missing_keys,
        "readability_warning_count": len(readability_warnings),
        "bad_validate_rc": bad_validate_rc,
        "bad_readability_warning_count": len(bad_readability_warnings),
        "missing_bad_warning_paths": missing_bad_warning_paths,
        "bad_planning_error_count": bad_planning_payload.get("error_count"),
        "bad_planning_warning_count": bad_planning_payload.get("warning_count"),
        "planning_error_count": planning_payload.get("error_count"),
        "planning_warning_count": planning_payload.get("warning_count"),
        "init_stdout_tail": init_out[-1200:],
        "validate_stdout_tail": validate_out[-1200:],
        "bad_validate_stdout_tail": bad_validate_out[-1200:],
    }


