    case_dir.mkdir(parents=True, exist_ok=True)
    (case_dir / "data").mkdir(parents=True, exist_ok=True)
    (case_dir / "assets" / "charts").mkdir(parents=True, exist_ok=True)
    (case_dir / "assets" / "tables").mkdir(parents=True, exist_ok=True)
    (case_dir / "assets" / "figures").mkdir(parents=True, exist_ok=True)

    data_path = case_dir / "data" / "readout.csv"
    script_path = case_dir / "assets" / "make_figures.py"
    chart_path = case_dir / "assets" / "charts" / "signal.json"
    table_path = case_dir / "assets" / "tables" / "signal_summary.json"
    figure_path = case_dir / "assets" / "figures" / "signal.png"
    data_path.write_text("Sample,Signal\nA,1.0\nB,2.0\n", encoding="utf-8")
    script_path.write_text("print('generate signal artifacts')\n", encoding="utf-8")
    chart_path.write_text(
        json.dumps(
            {
                "type": "bar",
                "title": "Signal",
                "categories": ["A", "B"],
                "values": [1.0, 2.0],
            },
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )
    table_path.write_text(
        json.dumps(
            {
                "title": "Signal summary",
                "headers": ["Sample", "Signal"],
                "rows": [["A", "1.0"], ["B", "2.0"]],
            },
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )
    figure_path.write_bytes(b"synthetic-png-placeholder")
    now = time.time()
    older = now - 10
    for path in (data_path, script_path):
        os.utime(path, (older, older))
    for path in (chart_path, table_path, figure_path):
        os.utime(path, (now, now))

    design_brief = {
        "topic": "Artifact Plan Duplicate List Regression",
        "design_dna": "lab results dashboard",
        "format_promise": "Warn when artifact plan lists repeat the same source, script, output, or command.",
        "structure_strategy": {
            "primary_scaffold": "lab report",
            "container_policy": "Use deterministic generated artifacts without repeated plan entries.",
        },
        "title_page_concept": {
            "chosen_archetype": "lab-plate",
            "dominant_element": "artifact list validation",
        },
        "figure_export_contract": {
            "script": "assets/make_figures.py",
            "rerun_command": "python3 assets/make_figures.py",
            "outputs": [
                {
                    "path": "assets/figures/signal.png",
                    "target_variant": "image-sidebar",
                    "target_box": "5.2x3.3 in",
                    "figure_size_inches": [6.4, 3.6],
                    "figure_dpi": 180,
                    "axis_label_min_pt": 8,
                    "crop_rule": "tight bbox, no exterior whitespace",
                },
                {
                    "path": "./assets/figures/signal.png",
                    "target_variant": "image-sidebar",
                    "target_box": "5.2x3.3 in",
                    "figure_size_inches": [6.4, 3.6],
                    "figure_dpi": 180,
                    "axis_label_min_pt": 8,
                    "crop_rule": "tight bbox, no exterior whitespace",
                },
            ],
        },
        "analysis_artifact_plan": {
            "candidate_data_files": ["data/readout.csv", "./data/readout.csv"],
            "spreadsheet_inputs": [],
            "required_scripts": ["assets/make_figures.py"],
            "figure_scripts": ["assets/make_figures.py", "./assets/make_figures.py"],
            "chart_json_outputs": ["assets/charts/signal.json", "./assets/charts/signal.json"],
            "table_outputs": ["assets/tables/signal_summary.json"],
            "rebuild_commands": ["python3 assets/make_figures.py", "python3  assets/make_figures.py"],
            "artifact_registry": [
                {
                    "id": "signal_figure",
                    "path": "assets/figures/signal.png",
                    "producer": "assets/make_figures.py",
                    "used_on_slides": ["s2"],
                    "provenance": "Synthetic figure fixture.",
                },
                {
                    "id": "signal_chart",
                    "path": "assets/charts/signal.json",
                    "producer": "assets/make_figures.py",
                    "used_on_slides": ["s2"],
                    "provenance": "Synthetic chart fixture.",
                },
                {
                    "id": "signal_table",
                    "path": "assets/tables/signal_summary.json",
                    "producer": "assets/make_figures.py",
                    "used_on_slides": ["s2"],
                    "provenance": "Synthetic table fixture.",
                },
            ],
        },
        "readability_contract": {
            "min_title_pt": 26,
            "min_body_pt": 16,
            "min_caption_pt": 8,
            "max_title_lines": 2,
            "footer_reserved_inches": 0.34,
            "chart_label_min_pt": 8,
            "table_density_rule": "split or summarize tables that force unreadable text",
            "whitespace_rule": "avoid awkward empty regions",
            "figure_crop_rule": "tight bounding boxes",
        },
        "speed_contract": {
            "renderer": "pptxgenjs",
            "first_pass": "validate planning before render",
            "render_policy": "render after artifacts are fresh",
            "asset_policy": "reuse local generated artifacts",
            "conversion_hint": "use persistent LibreOffice/unoserver when available for repeated render QA",
        },
    }
    for name, payload in (
        ("design_brief.json", design_brief),
        (
            "content_plan.json",
            {
                "thesis": "Duplicate artifact plan list entries should be surfaced before rendering.",
                "slide_plan": [],
            },
        ),
        ("evidence_plan.json", {"items": []}),
        ("asset_plan.json", {"topic": "Artifact Plan Duplicate List Regression"}),
        ("outline.json", {"title": "Artifact Plan Duplicate List Regression", "slides": []}),
    ):
        (case_dir / name).write_text(json.dumps(payload, indent=2) + "\n", encoding="utf-8")

    report_path = case_dir / "planning_report.json"
    validate_rc, validate_out = _run(
        [
            py,
            str(repo / "scripts" / "validate_planning.py"),
            "--workspace",
            str(case_dir),
            "--report",
            str(report_path),
        ]
    )
    payload = _load_json(report_path)
    issues = [item for item in payload.get("issues", []) if isinstance(item, dict)]
    messages = [str(item.get("message") or "") for item in issues]
    duplicate_entry_count = sum("duplicate entry" in message for message in messages)
    duplicate_figure_output_warning = any("duplicate figure output path" in message for message in messages)
    passed = (
        validate_rc == 1
        and payload.get("error_count") == 0
        and payload.get("warning_count") == 5
        and duplicate_entry_count == 4
        and duplicate_figure_output_warning
    )
    return {
        "case": "artifact-plan-duplicate-list-gate",
        "passed": passed,
        "workspace": str(case_dir),
        "validate_rc": validate_rc,
        "error_count": payload.get("error_count"),
        "warning_count": payload.get("warning_count"),
        "duplicate_entry_count": duplicate_entry_count,
        "duplicate_figure_output_warning": duplicate_figure_output_warning,
        "validate_stdout_tail": validate_out[-1200:],
    }


