def _run_footer_reserve_regression(repo: Path, outdir: Path, py: str) -> dict[str, Any]:
    case_dir = outdir / "footer-reserve-gate"
    if case_dir.exists():
        shutil.rmtree(case_dir)
    case_dir.mkdir(parents=True, exist_ok=True)
    pptx_path = case_dir / "footer-reserve.pptx"
    design_brief_path = case_dir / "design_brief.json"
    report_path = case_dir / "design_report.json"

    prs = Presentation()
    prs.slide_width = Inches(10)
    prs.slide_height = Inches(5.625)
    slide = prs.slides.add_slide(prs.slide_layouts[6])
    title = slide.shapes.add_textbox(Inches(0.7), Inches(0.35), Inches(8.6), Inches(0.45))
    title_tf = title.text_frame
    title_tf.text = "Footer Reserve Regression"
    title_tf.paragraphs[0].font.size = Pt(26)
    body = slide.shapes.add_textbox(Inches(0.8), Inches(4.35), Inches(7.6), Inches(0.75))
    body_tf = body.text_frame
    body_tf.text = "This body text intentionally intrudes into the reserved footer band."
    body_tf.paragraphs[0].font.size = Pt(16)
    footer = slide.shapes.add_textbox(Inches(0.7), Inches(5.32), Inches(8.6), Inches(0.22))
    footer_tf = footer.text_frame
    footer_tf.text = "Sources: synthetic regression fixture"
    footer_tf.paragraphs[0].font.size = Pt(8)
    prs.save(pptx_path)

    design_brief_path.write_text(
        json.dumps(
            {
                "readability_contract": {
                    "min_title_pt": 24,
                    "min_body_pt": 12,
                    "min_caption_pt": 7.5,
                    "chart_label_min_pt": 8,
                    "footer_reserved_inches": 1.0,
                }
            },
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )

    qa_rc, qa_out = _run(
        [
            py,
            str(repo / "scripts" / "design_rules_qa.py"),
            "--input",
            str(pptx_path),
            "--design-brief",
            str(design_brief_path),
            "--report",
            str(report_path),
        ]
    )
    payload = _load_json(report_path)
    issue_types = {
        str(item.get("type") or "")
        for item in payload.get("issues", [])
        if isinstance(item, dict)
    }
    passed = (
        qa_rc == 1
        and payload.get("error_count") == 0
        and "footer_reserved_space_intrusion" in issue_types
    )
    return {
        "case": "footer-reserve-gate",
        "passed": passed,
        "workspace": str(case_dir),
        "design_qa_rc": qa_rc,
        "error_count": payload.get("error_count"),
        "warning_count": payload.get("warning_count"),
        "issue_types": sorted(issue_types),
        "qa_stdout_tail": qa_out[-1200:],
    }


def _run_text_density_preflight_regression(repo: Path, outdir: Path, py: str) -> dict[str, Any]:
    case_dir = outdir / "text-density-preflight-gate"
    if case_dir.exists():
        shutil.rmtree(case_dir)
    case_dir.mkdir(parents=True, exist_ok=True)
    outline_path = case_dir / "outline.json"
    design_brief_path = case_dir / "design_brief.json"
    outline = {
        "title": "Text Density Preflight Regression",
        "slides": [
            {"type": "title", "title": "Text Density Preflight Regression"},
            {
                "type": "content",
                "variant": "standard",
                "title": "Overloaded prose should warn before render",
                "body": [
                    "The first bullet tries to carry method detail, cohort context, assay setup, and reviewer guidance all at once.",
                    "The second bullet adds run conditions, threshold assumptions, and an interpretation caveat that should move to notes.",
                    "The third bullet repeats execution detail with enough words to make the slide shrink below comfortable reading size.",
                    "The fourth bullet mixes provenance, versioning, quality checks, and limitations without giving the layout a visual anchor.",
                    "The fifth bullet continues the same long-form explanation instead of converting evidence into a compact chart or table.",
                    "The sixth bullet describes downstream decisions, audit trail requirements, and sample handling in sentence form.",
                    "The seventh bullet adds exception handling, unresolved questions, and a final recommendation that should be separated.",
                    "The eighth bullet keeps adding caveats until the slide becomes a leave-behind paragraph rather than a clean slide.",
                    "The ninth bullet proves the static preflight should catch the text overload before the renderer starts.",
                ],
            },
            {
                "type": "content",
                "variant": "standard",
                "title": "Single paragraph overload should still warn",
                "body": (
                    "This single paragraph packs assay setup, cohort filters, extraction batch handling, "
                    "reagent lot tracking, instrument operator variation, borderline sample adjudication, "
                    "repeat-call logic, reviewer reconciliation, source workbook provenance, threshold assumptions, "
                    "failure modes, and next-run decisions into one slide body instead of splitting the evidence "
                    "into a figure, table, or notes. It also keeps quality control caveats, sensitivity bounds, "
                    "specificity checks, concordance review, missing sample handling, run metadata, versioned "
                    "protocol context, and downstream interpretation in the same paragraph, so the rendered slide "
                    "would shrink into leave-behind prose even though the outline contains only one text field."
                ),
            },
        ],
    }
    outline_path.write_text(json.dumps(outline, indent=2) + "\n", encoding="utf-8")
    design_brief_path.write_text(
        json.dumps(
            {
                "readability_contract": {
                    "max_slide_text_lines": 12,
                    "max_slide_words": 190,
                    "max_slide_chars": 1250,
                }
            },
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )

    def run_preflight(label: str, *, with_design_brief: bool) -> tuple[subprocess.CompletedProcess[str], dict[str, Any], set[str]]:
        cmd = [
            py,
            str(repo / "scripts" / "preflight.py"),
            "--outline",
            str(outline_path),
        ]
        if with_design_brief:
            cmd.extend(["--design-brief", str(design_brief_path)])
        result = subprocess.run(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
        )
        report_path = case_dir / f"{label}_preflight.json"
        report_path.write_text(result.stdout, encoding="utf-8")
        payload = _load_json(report_path)
        rules = {
            str(item.get("rule") or "")
            for item in payload.get("issues", [])
            if isinstance(item, dict)
        }
        return result, payload, rules

    default_preflight, default_payload, default_rules = run_preflight(
        "default",
        with_design_brief=False,
    )
    contract_preflight, contract_payload, contract_rules = run_preflight(
        "contract",
        with_design_brief=True,
    )
    all_rules = {
        str(item.get("rule") or "")
        for item in [
            *(default_payload.get("issues", []) if isinstance(default_payload.get("issues"), list) else []),
            *(contract_payload.get("issues", []) if isinstance(contract_payload.get("issues"), list) else []),
        ]
        if isinstance(item, dict)
    }
    density_matches = [
        item
        for item in default_payload.get("issues", [])
        if isinstance(item, dict) and item.get("rule") == "content_text_density_high"
    ]
    density_slide_indexes = sorted(
        int(item.get("slide_index"))
        for item in density_matches
        if isinstance(item.get("slide_index"), int)
    )
    passed = (
        default_preflight.returncode == 1
        and default_payload.get("error_count") == 0
        and "content_text_density_high" in default_rules
        and density_slide_indexes == [1, 2]
        and contract_preflight.returncode == 0
        and contract_payload.get("error_count") == 0
        and contract_payload.get("warning_count") == 0
        and "content_text_density_high" not in contract_rules
    )
    return {
        "case": "text-density-preflight-gate",
        "passed": passed,
        "workspace": str(case_dir),
        "preflight_rc": default_preflight.returncode,
        "contract_preflight_rc": contract_preflight.returncode,
        "error_count": default_payload.get("error_count"),
        "warning_count": default_payload.get("warning_count"),
        "contract_error_count": contract_payload.get("error_count"),
        "contract_warning_count": contract_payload.get("warning_count"),
        "density_warning_count": len(density_matches),
        "density_slide_indexes": density_slide_indexes,
        "rules": sorted(all_rules),
        "default_rules": sorted(default_rules),
        "contract_rules": sorted(contract_rules),
        "preflight_stdout_tail": default_preflight.stdout[-1200:],
        "preflight_stderr_tail": default_preflight.stderr[-1200:],
        "contract_stdout_tail": contract_preflight.stdout[-1200:],
        "contract_stderr_tail": contract_preflight.stderr[-1200:],
    }


def _run_title_line_preflight_regression(repo: Path, outdir: Path, py: str) -> dict[str, Any]:
    case_dir = outdir / "title-line-preflight-gate"
    if case_dir.exists():
        shutil.rmtree(case_dir)
    case_dir.mkdir(parents=True, exist_ok=True)
    outline_path = case_dir / "outline.json"
    orphan_outline_path = case_dir / "orphan_outline.json"
    subtitle_outline_path = case_dir / "subtitle_outline.json"
    strict_brief_path = case_dir / "strict_design_brief.json"
    relaxed_brief_path = case_dir / "relaxed_design_brief.json"
    orphan_brief_path = case_dir / "orphan_design_brief.json"
    subtitle_brief_path = case_dir / "subtitle_design_brief.json"
    long_title = (
        "Detailed assay reproducibility readout across extraction batches, reagent lots, "
        "instrument operators, borderline samples, repeat calls, and review decisions"
    )
    orphan_title = "Assay reproducibility readout across extraction batches, lots, and operators"
    crowded_subtitle = (
        "Assay setup, cohort filters, extraction batch handling, reagent lot tracking, operator "
        "variation, borderline sample adjudication, repeat-call logic, and reviewer reconciliation "
        "are all packed into the header."
    )
    outline = {
        "title": "Title Line Preflight Regression",
        "slides": [
            {"type": "title", "title": "Title Line Preflight Regression"},
            {
                "type": "content",
                "variant": "standard",
                "title": long_title,
                "body": "The body is intentionally short so only the title contract is under test.",
            },
        ],
    }
    outline_path.write_text(json.dumps(outline, indent=2) + "\n", encoding="utf-8")
    orphan_outline = {
        "title": "Title Orphan Line Preflight Regression",
        "slides": [
            {"type": "title", "title": "Title Orphan Line Preflight Regression"},
            {
                "type": "content",
                "variant": "standard",
                "title": orphan_title,
                "body": "The body is intentionally short so only title wrapping polish is under test.",
            },
        ],
    }
    orphan_outline_path.write_text(json.dumps(orphan_outline, indent=2) + "\n", encoding="utf-8")
    subtitle_outline = {
        "title": "Subtitle Line Preflight Regression",
        "slides": [
            {"type": "title", "title": "Subtitle Line Preflight Regression"},
            {
                "type": "content",
                "variant": "standard",
                "title": "Subtitle should not crowd the header",
                "subtitle": crowded_subtitle,
                "body": "The body is short; the subtitle alone should trigger the header-crowding warning.",
            },
        ],
    }
    subtitle_outline_path.write_text(json.dumps(subtitle_outline, indent=2) + "\n", encoding="utf-8")
    strict_brief_path.write_text(
        json.dumps({"readability_contract": {"max_title_lines": 2}}, indent=2) + "\n",
        encoding="utf-8",
    )
    relaxed_brief_path.write_text(
        json.dumps({"readability_contract": {"max_title_lines": 4}}, indent=2) + "\n",
        encoding="utf-8",
    )
    orphan_brief_path.write_text(
        json.dumps({"readability_contract": {"max_title_lines": 2}}, indent=2) + "\n",
        encoding="utf-8",
    )
    subtitle_brief_path.write_text(
        json.dumps({"readability_contract": {"max_title_lines": 2}}, indent=2) + "\n",
        encoding="utf-8",
    )

    def run_preflight(
        label: str,
        brief_path: Path,
        target_outline_path: Path = outline_path,
    ) -> tuple[subprocess.CompletedProcess[str], dict[str, Any], set[str]]:
        result = subprocess.run(
            [
                py,
                str(repo / "scripts" / "preflight.py"),
                "--outline",
                str(target_outline_path),
                "--design-brief",
                str(brief_path),
            ],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
        )
        report_path = case_dir / f"{label}_preflight.json"
        report_path.write_text(result.stdout, encoding="utf-8")
        payload = _load_json(report_path)
        rules = {
            str(item.get("rule") or "")
            for item in payload.get("issues", [])
            if isinstance(item, dict)
        }
        return result, payload, rules

    strict_preflight, strict_payload, strict_rules = run_preflight("strict", strict_brief_path)
    relaxed_preflight, relaxed_payload, relaxed_rules = run_preflight("relaxed", relaxed_brief_path)
    orphan_preflight, orphan_payload, orphan_rules = run_preflight(
        "orphan",
        orphan_brief_path,
        orphan_outline_path,
    )
    subtitle_preflight, subtitle_payload, subtitle_rules = run_preflight(
        "subtitle",
        subtitle_brief_path,
        subtitle_outline_path,
    )
    title_matches = [
        item
        for item in strict_payload.get("issues", [])
        if isinstance(item, dict) and item.get("rule") == "title_line_budget_high"
    ]
    orphan_matches = [
        item
        for item in orphan_payload.get("issues", [])
        if isinstance(item, dict) and item.get("rule") == "title_orphan_final_line"
    ]
    subtitle_matches = [
        item
        for item in subtitle_payload.get("issues", [])
        if isinstance(item, dict) and item.get("rule") == "subtitle_line_budget_high"
    ]
    passed = (
        strict_preflight.returncode == 1
        and strict_payload.get("error_count") == 0
        and len(title_matches) == 1
        and title_matches[0].get("slide_index") == 1
        and relaxed_preflight.returncode == 0
        and relaxed_payload.get("error_count") == 0
        and relaxed_payload.get("warning_count") == 0
        and "title_line_budget_high" not in relaxed_rules
        and "title_too_long" not in strict_rules
        and "title_too_long" not in relaxed_rules
        and orphan_preflight.returncode == 1
        and orphan_payload.get("error_count") == 0
        and len(orphan_matches) == 1
        and orphan_matches[0].get("slide_index") == 1
        and "title_line_budget_high" not in orphan_rules
        and subtitle_preflight.returncode == 1
        and subtitle_payload.get("error_count") == 0
        and len(subtitle_matches) == 1
        and subtitle_matches[0].get("slide_index") == 1
        and "title_line_budget_high" not in subtitle_rules
    )
    return {
        "case": "title-line-preflight-gate",
        "passed": passed,
        "workspace": str(case_dir),
        "preflight_rc": strict_preflight.returncode,
        "relaxed_preflight_rc": relaxed_preflight.returncode,
        "orphan_preflight_rc": orphan_preflight.returncode,
        "subtitle_preflight_rc": subtitle_preflight.returncode,
        "error_count": strict_payload.get("error_count"),
        "warning_count": strict_payload.get("warning_count"),
        "relaxed_error_count": relaxed_payload.get("error_count"),
        "relaxed_warning_count": relaxed_payload.get("warning_count"),
        "orphan_error_count": orphan_payload.get("error_count"),
        "orphan_warning_count": orphan_payload.get("warning_count"),
        "subtitle_error_count": subtitle_payload.get("error_count"),
        "subtitle_warning_count": subtitle_payload.get("warning_count"),
        "title_warning_count": len(title_matches),
        "orphan_title_warning_count": len(orphan_matches),
        "subtitle_warning_count_matched": len(subtitle_matches),
        "rules": sorted(strict_rules | relaxed_rules | orphan_rules | subtitle_rules),
        "preflight_stdout_tail": strict_preflight.stdout[-1200:],
        "preflight_stderr_tail": strict_preflight.stderr[-1200:],
        "relaxed_stdout_tail": relaxed_preflight.stdout[-1200:],
        "relaxed_stderr_tail": relaxed_preflight.stderr[-1200:],
        "orphan_stdout_tail": orphan_preflight.stdout[-1200:],
        "orphan_stderr_tail": orphan_preflight.stderr[-1200:],
        "subtitle_stdout_tail": subtitle_preflight.stdout[-1200:],
        "subtitle_stderr_tail": subtitle_preflight.stderr[-1200:],
    }


def _run_placeholder_preflight_regression(repo: Path, outdir: Path, py: str) -> dict[str, Any]:
    case_dir = outdir / "placeholder-preflight-gate"
    if case_dir.exists():
        shutil.rmtree(case_dir)
    case_dir.mkdir(parents=True, exist_ok=True)
    dirty_outline_path = case_dir / "dirty_outline.json"
    clean_outline_path = case_dir / "clean_outline.json"
    dirty_outline = {
        "title": "Placeholder Preflight Regression",
        "slides": [
            {"type": "title", "title": "Placeholder Preflight Regression"},
            {
                "type": "content",
                "variant": "standard",
                "title": "TODO replace this heading",
                "body": [
                    "Lorem ipsum should not survive into a generated deck.",
                    "[insert chart here] before final delivery.",
                    "XXX marks another unfinished slide text marker.",
                ],
            },
        ],
    }
    clean_outline = {
        "title": "Placeholder Preflight Clean Regression",
        "slides": [
            {"type": "title", "title": "Placeholder Preflight Clean Regression"},
            {
                "type": "content",
                "variant": "standard",
                "title": "Validated readout is ready to render",
                "body": [
                    "Static preflight should allow normal short report text.",
                    "Unresolved production work belongs in notes.md, not visible slide text.",
                ],
            },
        ],
    }
    dirty_outline_path.write_text(json.dumps(dirty_outline, indent=2) + "\n", encoding="utf-8")
    clean_outline_path.write_text(json.dumps(clean_outline, indent=2) + "\n", encoding="utf-8")

    def run_preflight(path: Path) -> tuple[subprocess.CompletedProcess[str], dict[str, Any], set[str]]:
        result = subprocess.run(
            [
                py,
                str(repo / "scripts" / "preflight.py"),
                "--outline",
                str(path),
            ],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
        )
        report_path = case_dir / f"{path.stem}_preflight.json"
        report_path.write_text(result.stdout, encoding="utf-8")
        payload = _load_json(report_path)
        rules = {
            str(item.get("rule") or "")
            for item in payload.get("issues", [])
            if isinstance(item, dict)
        }
        return result, payload, rules

    dirty_preflight, dirty_payload, dirty_rules = run_preflight(dirty_outline_path)
    clean_preflight, clean_payload, clean_rules = run_preflight(clean_outline_path)
    dirty_matches = [
        item
        for item in dirty_payload.get("issues", [])
        if isinstance(item, dict) and item.get("rule") == "placeholder_marker_in_outline"
    ]
    passed = (
        dirty_preflight.returncode == 1
        and dirty_payload.get("error_count") == 0
        and len(dirty_matches) == 1
        and dirty_matches[0].get("slide_index") == 1
        and clean_preflight.returncode == 0
        and clean_payload.get("error_count") == 0
        and clean_payload.get("warning_count") == 0
        and "placeholder_marker_in_outline" not in clean_rules
    )
    return {
        "case": "placeholder-preflight-gate",
        "passed": passed,
        "workspace": str(case_dir),
        "preflight_rc": dirty_preflight.returncode,
        "clean_preflight_rc": clean_preflight.returncode,
        "error_count": dirty_payload.get("error_count"),
        "warning_count": dirty_payload.get("warning_count"),
        "clean_error_count": clean_payload.get("error_count"),
        "clean_warning_count": clean_payload.get("warning_count"),
        "placeholder_warning_count": len(dirty_matches),
        "rules": sorted(dirty_rules | clean_rules),
        "preflight_stdout_tail": dirty_preflight.stdout[-1200:],
        "preflight_stderr_tail": dirty_preflight.stderr[-1200:],
        "clean_stdout_tail": clean_preflight.stdout[-1200:],
        "clean_stderr_tail": clean_preflight.stderr[-1200:],
    }


def _run_table_density_preflight_regression(repo: Path, outdir: Path, py: str) -> dict[str, Any]:
    case_dir = outdir / "table-density-preflight-gate"
    if case_dir.exists():
        shutil.rmtree(case_dir)
    case_dir.mkdir(parents=True, exist_ok=True)
    outline_path = case_dir / "outline.json"
    headers = ["Sample", "Run", "Ct", "Signal", "Call", "Replicate", "Comment"]
    rows = [
        [f"S{i:02d}", "R1", f"{18 + i / 10:.1f}", f"{40 - i:.1f}", "Pass", str((i % 3) + 1), "Review"]
        for i in range(1, 9)
    ]
    outline = {
        "title": "Table Density Preflight Regression",
        "slides": [
            {"type": "title", "title": "Table Density Preflight Regression"},
            {
                "type": "content",
                "variant": "lab-run-results",
                "title": "Dense editable result table",
                "tables": [
                    {
                        "title": "Run readout",
                        "headers": headers,
                        "rows": rows,
                    }
                ],
                "sources": ["Synthetic preflight fixture"],
            },
        ],
    }
    outline_path.write_text(json.dumps(outline, indent=2) + "\n", encoding="utf-8")
    preflight = subprocess.run(
        [
            py,
            str(repo / "scripts" / "preflight.py"),
            "--outline",
            str(outline_path),
        ],
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        text=True,
    )
    preflight_rc = preflight.returncode
    preflight_out = preflight.stdout
    report_path = case_dir / "preflight.json"
    report_path.write_text(preflight_out, encoding="utf-8")
    payload = _load_json(report_path)
    rules = {
        str(item.get("rule") or "")
        for item in payload.get("issues", [])
        if isinstance(item, dict)
    }
    passed = (
        preflight_rc == 1
        and payload.get("error_count") == 0
        and "table_too_many_columns" in rules
        and "table_cell_budget_high" in rules
    )
    return {
        "case": "table-density-preflight-gate",
        "passed": passed,
        "workspace": str(case_dir),
        "preflight_rc": preflight_rc,
        "error_count": payload.get("error_count"),
        "warning_count": payload.get("warning_count"),
        "rules": sorted(rules),
        "preflight_stdout_tail": preflight_out[-1200:],
        "preflight_stderr_tail": preflight.stderr[-1200:],
    }


