def _run_preflight_json_cache_regression(repo: Path, outdir: Path, py: str) -> dict[str, Any]:
    case_dir = outdir / "preflight-json-cache-gate"
    if case_dir.exists():
        shutil.rmtree(case_dir)
    staged_dir = case_dir / "assets" / "staged"
    chart_path = staged_dir / "charts" / "signal.json"
    table_path = staged_dir / "tables" / "summary.json"
    chart_path.parent.mkdir(parents=True, exist_ok=True)
    table_path.parent.mkdir(parents=True, exist_ok=True)
    chart_path.write_text(
        json.dumps({"title": "Signal", "categories": ["A", "B"], "values": [1, 2]}, indent=2) + "\n",
        encoding="utf-8",
    )
    table_path.write_text(
        json.dumps({"headers": ["Metric", "Value"], "rows": [["A", "1"], ["B", "2"]]}, indent=2) + "\n",
        encoding="utf-8",
    )
    manifest_path = staged_dir / "staged_manifest.json"
    manifest_path.write_text(
        json.dumps(
            {
                "workspace_assets_version": 1,
                "charts": [{"name": "signal", "path": str(chart_path)}],
                "tables": [{"name": "summary", "path": str(table_path)}],
                "images": [],
                "backgrounds": [],
                "generated_images": [],
            },
            indent=2,
        )
        + "\n",
        encoding="utf-8",
    )
    probe = f"""
import json
import sys
from collections import Counter
from pathlib import Path

sys.path.insert(0, {str(repo / "scripts")!r})
import preflight

workspace = Path({str(case_dir)!r})
calls = []
original_reader = preflight._read_json_object

def counted_reader(path):
    resolved = str(Path(path).resolve())
    calls.append(resolved)
    return original_reader(path)

preflight._read_json_object = counted_reader
outline = {{
    "title": "Preflight JSON Cache Regression",
    "slides": [
        {{"type": "title", "title": "Preflight JSON Cache Regression"}},
        {{"type": "content", "variant": "chart", "title": "Chart A", "assets": {{"chart_data": "chart:signal"}}}},
        {{"type": "content", "variant": "chart", "title": "Chart B", "assets": {{"chart_data": "chart:signal"}}}},
        {{"type": "content", "variant": "table", "title": "Table A", "table": "table:summary", "sources": ["Synthetic"]}},
        {{"type": "content", "variant": "table", "title": "Table B", "table": "table:summary", "sources": ["Synthetic"]}},
    ],
}}
issues = preflight.lint_outline(outline, workspace)
counts = Counter(calls)
print(json.dumps({{
    "error_count": sum(1 for item in issues if item.get("severity") == "error"),
    "warning_count": sum(1 for item in issues if item.get("severity") == "warning"),
    "read_count": len(calls),
    "max_reads_per_path": max(counts.values(), default=0),
    "paths": sorted(Path(path).name for path in counts),
    "counts": counts,
}}))
"""
    rc, out = _run([py, "-c", probe])
    try:
        payload = json.loads(out.strip().splitlines()[-1])
    except (IndexError, json.JSONDecodeError):
        payload = {}
    expected_paths = {"signal.json", "staged_manifest.json", "summary.json"}
    passed = (
        rc == 0
        and payload.get("error_count") == 0
        and payload.get("read_count") == 3
        and payload.get("max_reads_per_path") == 1
        and set(payload.get("paths") or []) == expected_paths
    )
    return {
        "case": "preflight-json-cache-gate",
        "passed": passed,
        "workspace": str(case_dir),
        "rc": rc,
        "error_count": payload.get("error_count"),
        "warning_count": payload.get("warning_count"),
        "read_count": payload.get("read_count"),
        "max_reads_per_path": payload.get("max_reads_per_path"),
        "paths": payload.get("paths"),
        "stdout_tail": out[-1200:],
    }


