def _set_textbox_text(shape: Any, text: str, *, font_size: float, color: RGBColor) -> None:
    frame = shape.text_frame
    frame.clear()
    paragraph = frame.paragraphs[0]
    run = paragraph.add_run()
    run.text = text
    run.font.size = Pt(font_size)
    run.font.color.rgb = color


def _set_shape_color(shape: Any, color: RGBColor) -> None:
    shape.fill.solid()
    shape.fill.fore_color.rgb = color
    shape.line.color.rgb = color


def _write_synthetic_style_reference_pptx(pptx_path: Path) -> None:
    prs = Presentation()
    prs.slide_width = Inches(13.333)
    prs.slide_height = Inches(7.5)
    blank = prs.slide_layouts[6]
    navy = RGBColor(11, 37, 69)
    red = RGBColor(201, 48, 44)
    muted = RGBColor(75, 85, 99)
    text = RGBColor(27, 40, 56)
    for idx, title in enumerate(
        [
            "Template Signal: Run Summary",
            "Template Signal: Evidence Table",
            "Template Signal: Interpretation",
        ],
        start=1,
    ):
        slide = prs.slides.add_slide(blank)
        title_box = slide.shapes.add_textbox(Inches(0.7), Inches(0.32), Inches(8.3), Inches(0.42))
        _set_textbox_text(title_box, title, font_size=28, color=text)
        accent = slide.shapes.add_shape(MSO_SHAPE.RECTANGLE, Inches(0.7), Inches(0.88), Inches(11.9), Inches(0.03))
        _set_shape_color(accent, red if idx == 2 else navy)
        footer_rule = slide.shapes.add_shape(MSO_SHAPE.RECTANGLE, Inches(0.7), Inches(7.05), Inches(11.9), Inches(0.02))
        _set_shape_color(footer_rule, navy)
        footer = slide.shapes.add_textbox(Inches(0.7), Inches(7.08), Inches(10.5), Inches(0.22))
        _set_textbox_text(footer, "Sources: SYN01; Refs: synthetic regression", font_size=8, color=muted)
        page = slide.shapes.add_textbox(Inches(12.0), Inches(7.08), Inches(0.6), Inches(0.22))
        _set_textbox_text(page, f"{idx}/3", font_size=8.4, color=muted)
        body = slide.shapes.add_textbox(Inches(0.9), Inches(1.35), Inches(5.2), Inches(0.7))
        _set_textbox_text(body, "Compact evidence text with report-sized body type.", font_size=14, color=text)
        if idx == 2:
            table_shape = slide.shapes.add_table(2, 2, Inches(0.9), Inches(2.25), Inches(4.8), Inches(0.8))
            table = table_shape.table
            table.cell(0, 0).text = "Metric"
            table.cell(0, 1).text = "Value"
            table.cell(1, 0).text = "Pass rate"
            table.cell(1, 1).text = "92%"
    prs.save(str(pptx_path))


def _run_pptx_style_extraction_regression(repo: Path, outdir: Path, py: str) -> dict[str, Any]:
    case_dir = outdir / "pptx-style-extraction-gate"
    if case_dir.exists():
        shutil.rmtree(case_dir)
    case_dir.mkdir(parents=True, exist_ok=True)
